var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。`,ENG:`that you'll be with her, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called her to your office. She said she'd be here soon.`,TWN:`做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`XIAOLIN_ALT_ReinforcedB_NULL`,text:{KOREA:`사장님도 정말 변함없으시네요.`,JPN:`社長はいつも変わらないですね。`,ENG:`You never change, Boss.`,TWN:`老闆真是完全沒變呢。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`XIAOLIN_ALT_ReinforcedB_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`XIAOLIN_ALT_ReinforcedB_NULL`,text:{KOREA:`그래서 오늘은 무슨 용건으로 부르셨죠?`,JPN:`それで、本日はどういったご用件でしょう？`,ENG:`So, what can I do for you today?`,TWN:`所以，今天您找我有什麼事？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`XIAOLIN_ALT_ReinforcedB_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`XIAOLIN_ALT_ReinforcedB_NULL`,text:{KOREA:`......종신계약이요?`,JPN:`……終身契約ですか？`,ENG:`A lifetime contract?`,TWN:`……終身契約嗎？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`XIAOLIN_ALT_ReinforcedB_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`XIAOLIN_ALT_ReinforcedB_NULL`,text:{KOREA:`무슨 뜻인지는 알아요. 업계에선 사실상 청혼이나 마찬가지라고 해서 꽤 유명하니까요.`,JPN:`言葉の意味は分かります。この業界では事実上の求婚として知られています。`,ENG:`I know what it means. In fact, it's the same as popping the question in this industry.`,TWN:`我知道這是什麼意思。這在業界實際上就跟求婚一樣，非常有名呢。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`XIAOLIN_ALT_ReinforcedB_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`XIAOLIN_ALT_ReinforcedB_NULL`,text:{KOREA:`알겠습니다. 받아들이죠.`,JPN:`分かりました。お受けします。`,ENG:`Okay, I'll sign it.`,TWN:`我知道了。我接受。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`XIAOLIN_ALT_ReinforcedB_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`XIAOLIN_ALT_ReinforcedB_NULL`,text:{KOREA:`네? 제가 선뜻 받아들이는 게 그렇게 이상한가요?`,JPN:`はい？　私があっさり承諾したことがそんなに意外ですか？`,ENG:`Excuse me? Are you surprised that I'm so willing?`,TWN:`咦？我這麼乾脆地接受，會有那麼奇怪嗎？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`XIAOLIN_ALT_ReinforcedB_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`XIAOLIN_ALT_ReinforcedB_NULL`,text:{KOREA:`흠, 흠. 여, 여기만큼 느슨한 회사도 찾기 어렵거든요.`,JPN:`こ、ここ以上にゆるい職場はそうそうありませんので。`,ENG:`Well... *Ahem* I-it's difficult to find a company as relaxed as yours.`,TWN:`嗯，嗯……因、因為也很難找到第二家像這裡這麼輕鬆的公司了。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`XIAOLIN_ALT_ReinforcedB_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`XIAOLIN_ALT_ReinforcedB_NULL`,text:{KOREA:`그리고 애초에, 이런 분인 줄 알았다면 제가 먼저......`,JPN:`それに、こんな方だと分かっていたら、そもそも私の方から……`,ENG:`And I'd probably have popped the question first if I knew you were like this—`,TWN:`而且，如果我從一開始就知道您是這樣的人，我就先……`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`XIAOLIN_ALT_ReinforcedB_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`XIAOLIN_ALT_ReinforcedB_NULL`,text:{KOREA:`아, 아무것도 아닙니다. 계약서 먼저 주세요.`,JPN:`な、何でもありません。とにかく契約書を渡してください。`,ENG:`Never mind. Please give me the contract.`,TWN:`沒、沒什麼。請先給我契約書吧。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`XIAOLIN_ALT_ReinforcedB_NULL`,face:`UNIT_HATE`},R:null}}}];export{e as default};